1199	func (s *Server) handleListBeads(w http.ResponseWriter, r *http.Request) {
1200		status := r.URL.Query().Get("status")
1201		label := r.URL.Query().Get("label")
1202		projectFilter := r.URL.Query().Get("project_id")
1203	
1204		// Scoped route injects a project into context; pin the filter to it so the
1205		// handler only emits beads from that project.
1206		if p, ok := projectFromContext(r.Context()); ok {
1207			projectFilter = p.ID
1208		}
1209	
1210		projects := s.state.GetProjects()
1211		var result []beadWithProject
1212	
1213		for _, proj := range projects {
1214			if projectFilter != "" && proj.ID != projectFilter {
1215				continue
1216			}
1217			store := bead.NewStore(filepath.Join(proj.Path, ".ddx"))
1218			beads, err := store.ReadAll()
1219			if err != nil {
1220				continue
1221			}
1222			for _, b := range beads {
1223				if status != "" && b.Status != status {
1224					continue
1225				}
1226				if label != "" && !containsString(b.Labels, label) {
1227					continue
1228				}
1229				result = append(result, beadWithProject{Bead: b, ProjectID: proj.ID})
1230			}
1231		}
1232	
1233		if result == nil {
1234			result = []beadWithProject{}
1235		}
1236		writeJSON(w, http.StatusOK, result)
1237	}
